import { Component, OnInit } from "@angular/core";
import { AlertService } from "src/app/core/services/alert.service";
import { LoansService } from "src/app/core/services/loans.service";
import { pagingService } from "src/app/core/services/paging.service";
import { LoanTypeRef } from "src/app/views/Models/Loan/LoanType";
import { User } from "src/app/views/Models/Permissions/User";

interface UserSearchInterface {
  visible: boolean;
  selectedUser: User;
}
interface SelectedUserInterface {
  loanTypesThatHasPermissionOnIt: LoanTypeRef[];
}

@Component({
  selector: "app-add-loan-types-for-user",
  templateUrl: "./add-loan-types-for-user.page.html",
  styleUrls: ["./add-loan-types-for-user.page.scss"],
})
export class AddLoanTypesForUserPage implements OnInit {
  constructor(
    private loanService: LoansService,
    private alertService: AlertService,
    private pagingService: pagingService
  ) {}

  //#region Variables
  showLoader: boolean = false;
  userSearch: UserSearchInterface;
  pagingObject: { pageSize: number; page: number };
  allLoanTypes: { count: number; result: LoanTypeRef[] };
  selectedUser: SelectedUserInterface;
  //#endregion

  async ngOnInit() {
    this.showLoader = true;
    this.initializeState();
    this.allLoanTypes = await this.loanService
      .getAllLoanTypes(this.pagingObject.page, this.pagingObject.pageSize)
      .toPromise();
    this.showLoader = false;
    console.log(this.allLoanTypes, this.showLoader);
  }

  async initializeState() {
    this.userSearch = {
      visible: true,
      selectedUser: null,
    };
    this.pagingObject = {
      page: 1, // the page we are viewing
      pageSize: this.pagingService.getPageSizeFromLocalStorage(), // number of viewed results
    };
    this.selectedUser = { loanTypesThatHasPermissionOnIt: [] };
    this.allLoanTypes = await this.loanService
      .getAllLoanTypes(this.pagingObject.page, this.pagingObject.pageSize)
      .toPromise();
  }

  async userSelected($event: User) {
    try {
      this.showLoader = true;
      this.userSearch.selectedUser = $event;
      this.selectedUser.loanTypesThatHasPermissionOnIt = await this.loanService
        .getAllLoansTypeForSpecificUser(this.userSearch.selectedUser.user_name)
        .toPromise();

      this.userSearch.visible = false;
    } catch (error) {
      console.error(error);
      this.alertService.showAlertError(
        error?.message || "حدث خطا في البيانات",
        false
      );
    } finally {
      this.showLoader = false;
    }
  }
  backButton() {
    if (!this.userSearch.visible) {
      this.initializeState();
    }
  }
  changePaginationPage = async (newPage: number): Promise<void> => {
    this.pagingObject.page = newPage;
    try {
      this.showLoader = true;
      this.allLoanTypes = await this.loanService
        .getAllLoanTypes(this.pagingObject.page, this.pagingObject.pageSize)
        .toPromise();
    } catch (error) {
      console.log("error", error);
      this.alertService.showAlertError(
        error?.message || "حدث خطا في البيانات",
        false
      );
    } finally {
      this.showLoader = false;
    }
  };

  async removeAllPermissionsFromUserBtn() {
    try {
      this.showLoader = true;
      var alertText = "إلغاء";
      if (
        !(await this.alertService.SaveAlert(
          `هل تريد ${alertText} جميع الصلاحيات؟`
        ))
      ) {
        this.showLoader = false;
        return;
      }
      await this.loanService
        .manageUserAllLoanTypePermission(
          this.userSearch.selectedUser.user_name,
          1
        )
        .toPromise();
      this.selectedUser.loanTypesThatHasPermissionOnIt = await this.loanService
        .getAllLoansTypeForSpecificUser(this.userSearch.selectedUser.user_name)
        .toPromise();
    } catch (error) {
      console.error(error);
      this.alertService.showAlertError(error?.message || "حدث خطا", false);
    } finally {
      this.showLoader = false;
    }
  }
  async giveAllPermissionsToUserBtn() {
    try {
      this.showLoader = true;
      var alertText = "منح";
      if (
        !(await this.alertService.SaveAlert(
          `هل تريد ${alertText} جميع الصلاحيات؟`
        ))
      ) {
        this.showLoader = false;
        return;
      }
      await this.loanService
        .manageUserAllLoanTypePermission(
          this.userSearch.selectedUser.user_name,
          2
        )
        .toPromise();
      this.selectedUser.loanTypesThatHasPermissionOnIt = await this.loanService
        .getAllLoansTypeForSpecificUser(this.userSearch.selectedUser.user_name)
        .toPromise();
    } catch (error) {
      console.error(error);
      this.alertService.showAlertError(error?.message || "حدث خطا", false);
    } finally {
      this.showLoader = false;
    }
  }
  checkIfClientHasPermissionOnSpecificLoanType = (
    loanTypeCode: string
  ): boolean => {
    return this.selectedUser.loanTypesThatHasPermissionOnIt.some(
      (loanType) => loanType.loan_type_code === loanTypeCode
    );
  };
  async removePermissionOnSpecificLoanType(loanTypeCode: string) {
    try {
      this.showLoader = true;
      await this.loanService
        .manageUserLoanTypePermission(
          this.userSearch.selectedUser.user_name,
          Number(loanTypeCode),
          1
        )
        .toPromise();
      const loanTypeIndex =
        this.selectedUser.loanTypesThatHasPermissionOnIt.findIndex(
          (loanType) => loanType.loan_type_code === loanTypeCode
        );
      this.selectedUser.loanTypesThatHasPermissionOnIt.splice(loanTypeIndex, 1);
    } catch (error) {
      this.alertService.showAlertError(error.message, false);
    } finally {
      this.showLoader = false;
    }
  }
  async addPermissionOnSpecificLoanType(loanTypeCode: string) {
    try {
      this.showLoader = true;
      await this.loanService
        .manageUserLoanTypePermission(
          this.userSearch.selectedUser.user_name,
          Number(loanTypeCode),
          2
        )
        .toPromise();
      this.selectedUser.loanTypesThatHasPermissionOnIt.push(
        this.getLoanTypeInformation(loanTypeCode)
      );
    } catch (error) {
      this.alertService.showAlertError(error.message, false);
    } finally {
      this.showLoader = false;
    }
  }
  getLoanTypeInformation = (loanTypeCode: string): LoanTypeRef => {
    const loanTypeInfo = this.allLoanTypes.result.find(
      (loanType) => loanType.loan_type_code === loanTypeCode
    );
    return loanTypeInfo;
  };
  toggleEnableAllOrDisableAllBtn(): {
    disableRemoveAllLoanTypesPermissionBtn: boolean;
    disableAddAllLoanTypesPermissionBtn: boolean;
  } {
    return {
      disableRemoveAllLoanTypesPermissionBtn:
        this.selectedUser.loanTypesThatHasPermissionOnIt.length ===
        this.allLoanTypes.count,
      disableAddAllLoanTypesPermissionBtn:
        this.selectedUser.loanTypesThatHasPermissionOnIt.length === 0,
    };
  }
}
